class TestSevenYearBoundary:
    """Explicit boundary tests around the 7-year threshold."""

    @pytest.mark.parametrize("delta,expected_storage", [
        (relativedelta(years=6, months=11, days=29), "hot"),   # just under 7 years
        (relativedelta(years=7),                                "cold"),  # exactly 7 years
        (relativedelta(years=7, days=1),                        "cold"),  # just over 7 years
        (relativedelta(years=7, months=1),                      "cold"),  # 7 years 1 month
