        period = date(period_dt.year, period_dt.month, 1)

        mock_hot_storage.fetch.return_value = sample_pdf_bytes
        mock_cold_storage.fetch.return_value = sample_pdf_bytes

        statement_service.get_statement(customer=valid_customer, period=period)

        if expected_storage == "hot":
            mock_hot_storage.fetch.assert_called_once()
            mock_cold_storage.fetch.assert_not_called()
        else:
            mock_cold_storage.fetch.assert_called_once()
