class TestColdStorageRetrievalMechanics:
    """Cold storage fetch may be asynchronous / require a restore step."""

    def test_cold_storage_restore_is_triggered_before_fetch(
        self, statement_service, valid_customer, old_period, sample_pdf_bytes,
        mock_cold_storage
